import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, MinusCircle, X, ShoppingCart, Calendar, Tag } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [lista, setLista] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ 
    descricao: '', 
    valor: '', 
    categoria: 'Moradia', 
    data: new Date().toISOString().split('T')[0] 
  });

  useEffect(() => {
    buscarDespesas();
  }, []);

  async function buscarDespesas() {
    setLoading(true);
    const { data } = await supabase.from('despesas').select('*').order('data_vencimento', { ascending: false });
    setLista(data || []);
    setLoading(false);
  }

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();
    
    const { error } = await supabase.from('despesas').insert([{
      user_id: user.id,
      descricao: form.descricao,
      valor: parseFloat(form.valor),
      categoria: form.categoria,
      data_vencimento: form.data
    }]);

    if (!error) {
      setForm({ ...form, descricao: '', valor: '' });
      setShowModal(false);
      buscarDespesas();
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  return (
    <div className="despesas-container fade-in">
      <header className="despesas-header">
        <div>
          <h2>Despesas e Custos</h2>
          <p>Controle seus gastos fixos</p>
        </div>
        <div className="header-total-box expense">
          <span className="label-total exp">Total Gasto</span>
          <span className="value-total exp">
            {formatMoney(lista.reduce((acc, cur) => acc + parseFloat(cur.valor), 0))}
          </span>
        </div>
      </header>

      <div className="despesas-card list-full-section">
        <h3>Lista de Pagamentos</h3>
        <div className="scroll-list-large">
          {loading ? (
            <div className="loading-msg">Carregando despesas...</div>
          ) : lista.length > 0 ? (
            lista.map(item => (
              <div key={item.id} className="expense-item-row">
                <div className="exp-icon"><ShoppingCart size={20} /></div>
                <div className="expense-info">
                  <span className="exp-desc">{item.descricao}</span>
                  <span className="exp-cat">{item.categoria} • {new Date(item.data_vencimento).toLocaleDateString()}</span>
                </div>
                <span className="exp-value">{formatMoney(item.valor)}</span>
              </div>
            ))
          ) : (
            <div className="empty-state">Nenhum gasto registrado.</div>
          )}
        </div>
      </div>

      <button className="fab-button expense" onClick={() => setShowModal(true)}>
        <Plus size={28} />
      </button>

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content side-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="modal-header-simple">
              <h3>Nova Despesa</h3>
              <button className="close-btn" onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>
            
            <form onSubmit={handleSalvar} className="modal-form">
              <div className="input-group">
                <label>Item</label>
                <input type="text" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} placeholder="Ex: Aluguel" />
              </div>
              <div className="input-group">
                <label>Valor</label>
                <input type="number" step="0.01" required value={form.valor} onChange={e => setForm({...form, valor: e.target.value})} placeholder="0,00" />
              </div>
              <div className="input-group">
                <label>Categoria</label>
                <select value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
                  <option value="Moradia">Moradia</option>
                  <option value="Alimentação">Alimentação</option>
                  <option value="Lazer">Lazer</option>
                  <option value="Saúde">Saúde</option>
                </select>
              </div>
              <div className="input-group">
                <label>Vencimento</label>
                <input type="date" required value={form.data} onChange={e => setForm({...form, data: e.target.value})} />
              </div>
              <button type="submit" className="btn-confirm-expense">Registrar Gasto</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Despesas;
